import java.util.ArrayList;

public class ZAlgorithm {
    public static int[] zAlgorithm(String text) {
        int n = text.length();
        int[] Z = new int[n];
        int l = 0, r = 0;
        for (int i = 1; i < n; i++) {
            if (i <= r) {
                Z[i] = Math.min(r - i + 1, Z[i - l]);
            }
            while (i + Z[i] < n && text.charAt(Z[i]) == text.charAt(i + Z[i])) {
                Z[i]++;
            }
            if (i + Z[i] - 1 > r) {
                l = i;
                r = i + Z[i] - 1;
            }
        }
        return Z;
    }

    public static void main(String[] args) {
        String text = "aaababa";
        String pattern = "aba";
        String combined = pattern + "$" + text;
        int[] z = zAlgorithm(combined);
        ArrayList<Integer> matches = new ArrayList<>();
        for (int i = 0; i < combined.length(); i++) {
            if (z[i] == pattern.length()) matches.add(i - pattern.length() - 1);
        }
        System.out.println("Pattern found at indices: " + matches);
    }
}
