#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int* zAlgorithm(const char* text, int n) {
    int* Z = (int*)calloc(n, sizeof(int));
    int l = 0, r = 0;
    for (int i = 1; i < n; i++) {
        if (i <= r) {
            Z[i] = (r - i + 1 < Z[i - l]) ? r - i + 1 : Z[i - l];
        }
        while (i + Z[i] < n && text[Z[i]] == text[i + Z[i]]) {
            Z[i]++;
        }
        if (i + Z[i] - 1 > r) {
            l = i;
            r = i + Z[i] - 1;
        }
    }
    return Z;
}

int main() {
    const char* text = "aaababa";
    const char* pattern = "aba";
    char* combined = (char*)malloc(strlen(pattern) + strlen(text) + 2);
    strcpy(combined, pattern);
    strcat(combined, "$");
    strcat(combined, text);
    int n = strlen(combined);
    int* z = zAlgorithm(combined, n);
    printf("Pattern found at indices: [");
    int first = 1;
    for (int i = 0; i < n; i++) {
        if (z[i] == strlen(pattern)) {
            if (!first) printf(", ");
            printf("%d", i - strlen(pattern) - 1);
            first = 0;
        }
    }
    printf("]\n");
    free(z);
    free(combined);
    return 0;
}
